import{_ as a,o as t,c as o,a3 as r}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"60. Purchased Leave","description":"","frontmatter":{"title":"60. Purchased Leave","eba":"Nurses and Midwives 2024-2028","topics":["leave"]},"headers":[],"relativePath":"ebas/nurses-midwives/leave/60-purchased-leave.md","filePath":"ebas/nurses-midwives/leave/60-purchased-leave.md"}'),n={name:"ebas/nurses-midwives/leave/60-purchased-leave.md"};function s(p,e,l,d,i,h){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="_60-purchased-leave" tabindex="-1">60. Purchased Leave <a class="header-anchor" href="#_60-purchased-leave" aria-label="Permalink to &quot;60. Purchased Leave&quot;">​</a></h1><p>This clause does not apply to casual Employees.</p><p><strong>60.1</strong> An Employee may, if mutually agreed with the Employer, purchase up to 20 working days (pro-rated for part-time Employees) additional paid leave in a 12-month period at ordinary pay. The additional paid leave is purchased through salary deductions made over the whole year. The amount deducted will correspond with the amount of leave purchased.</p><p>Example: An Employee who purchased four (4) additional weeks&#39; leave would be paid:</p><p><strong>(a)</strong> 48/52; or</p><p><strong>(b)</strong> 92.31% of the ordinary rate of pay throughout the relevant 12- month period. If an Employee purchased an additional two (2) weeks&#39; leave, the Employee would be paid 50/52; or</p><p><strong>(c)</strong> 96.15% of the ordinary rate of pay throughout the relevant 12-month period.</p><p><strong>60.2</strong> Purchased leave may be taken in conjunction with other types of leave.</p><p><strong>60.3</strong> Purchased leave must be used in the 12-month period in which it is purchased.</p><p><strong>60.4</strong> The Employer may grant purchased leave for a 12-month period, subject to operational requirements. Once approval has been granted, the arrangement may only be varied or cancelled in extraordinary circumstances.</p><p><strong>60.5</strong> Where the:</p><p><strong>(a)</strong> arrangement has been varied or cancelled because of extraordinary circumstances;</p><p><strong>(b)</strong> Employee&#39;s employment terminates; or</p><p><strong>(c)</strong> purchased leave has not been taken in the relevant 12-month period,</p><p>the Employer will refund the amount of salary deducted in respect of any unused purchased leave as a lump sum. In the case of variation or cancellation, payment will be made no later than two pay periods following notification of the variation or cancellation.</p><p><strong>60.6</strong> Where the Employee&#39;s employment terminates and the amount of purchased leave taken exceeds the amount deducted, the Employer may deduct a sum equal to the negative balance from any remuneration payable to the Employee upon termination of employment.</p><p>Plain language terms: 48/52, buying leave, extra leave, leave purchase.</p>',17)])])}const m=a(n,[["render",s]]);export{c as __pageData,m as default};
